var e=[{id:`L7_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`크윽!`,JPN:`くうっ！`,ENG:`Hngh!`,TWN:`唔！`},stage:{bg:`CORRIDOR_03`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`HOLY_KNIGHT_NULL_NULL`,text:{KOREA:`방금까지 저급한 4종 침식체도 간신히 상대하는 수준이었는데…….`,JPN:`先ほどまでは第4種侵食体になんとか対抗できる程度でしたが……`,ENG:`You could barely face off with a lowly Category 4 just moments ago…`,TWN:`剛剛和4類侵蝕體交手時明明還很勉強……`},stage:{bg:`CORRIDOR_03`,slots:{L:null,C:{char_id:`HOLY_KNIGHT_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`HOLY_KNIGHT_NULL_NULL`,text:{KOREA:`짧은 시간에 급격히 성장했군요.`,JPN:`この短時間で急激に成長したようですね。`,ENG:`How rapidly you've grown in such a short span of time.`,TWN:`在這麼短的時間內成長不少呢！`},stage:{bg:`CORRIDOR_03`,slots:{L:null,C:{char_id:`HOLY_KNIGHT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`HOLY_KNIGHT_NULL_NULL`,text:{KOREA:`이것도 그 저주받은 늑대로서의 힘인가요?`,JPN:`これも呪われた狼としての力でしょうか？`,ENG:`Is this also a perk of being the Cursed Wolf?`,TWN:`那也是因為你是受到詛咒的狼嗎？`},stage:{bg:`CORRIDOR_03`,slots:{L:null,C:{char_id:`HOLY_KNIGHT_NULL_NULL`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`알 바 아냐, 그딴 거!`,JPN:`そんなもの知らない！`,ENG:`I don't know, and I don't care!`,TWN:`不關你的事！`},stage:{bg:`CORRIDOR_03`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`지금 내가 아는 건 여기서 널 쓰러트린다는 것뿐이야!`,JPN:`今確かなのは、あんたをここで倒してやるってことだけ！`,ENG:`All I know is that I'm going to take you down right here!`,TWN:`我現在只知道一件事，就是要打倒你！`},stage:{bg:`CORRIDOR_03`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`HOLY_KNIGHT_NULL_NULL`,text:{KOREA:`후후…… 귀엽군요.`,JPN:`ふふ……かわいいものですね。`,ENG:`Haha… How amusing.`,TWN:`呵呵……真是可愛。`},stage:{bg:`CORRIDOR_03`,slots:{L:null,C:{char_id:`HOLY_KNIGHT_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`HOLY_KNIGHT_NULL_NULL`,text:{KOREA:`성장했다고는 하지만 그래 봐야 아직은 부족한 힘.`,JPN:`成長したとはいえ、まだ未熟の力。`,ENG:`You may have grown stronger, but your powers are still not enough.`,TWN:`雖說有成長不少，但能力還是有限。`},stage:{bg:`CORRIDOR_03`,slots:{L:null,C:{char_id:`HOLY_KNIGHT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`HOLY_KNIGHT_NULL_NULL`,text:{KOREA:`그 이방인의 말대로 찌꺼기에 불과한 주제에 자신감만은 넘치는군요.`,JPN:`あの異邦人の言うとおり、残滓にすぎないというのに自信だけは溢れていますね。`,ENG:`Like the outsider said, you're brimming with confidence despite being merely residue.`,TWN:`明明是個廢渣口氣卻不小呢。`},stage:{bg:`CORRIDOR_03`,slots:{L:null,C:{char_id:`HOLY_KNIGHT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`뭐라고?`,JPN:`何だって？`,ENG:`What?`,TWN:`你說我什麼？`},stage:{bg:`CORRIDOR_03`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`HOLY_KNIGHT_NULL_NULL`,text:{KOREA:`좋습니다. 장난은 이만 끝내기로 하지요.`,JPN:`いいでしょう。お遊びはこれでおしまいです。`,ENG:`Very well. Playtime is over.`,TWN:`好了，玩笑話到此為止。`},stage:{bg:`CORRIDOR_03`,slots:{L:null,C:{char_id:`HOLY_KNIGHT_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`HOLY_KNIGHT_NULL_NULL`,text:{KOREA:`어차피 우리에게 필요한 것은 당신의 몸뚱이뿐.`,JPN:`私たちに必要なものはあなたの体だけ。`,ENG:`All we need is your body, after all.`,TWN:`反正我們要的只有你的身體而已。`},stage:{bg:`CORRIDOR_03`,slots:{L:null,C:{char_id:`HOLY_KNIGHT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`HOLY_KNIGHT_NULL_NULL`,text:{KOREA:`뇌를 파내어 이지를 상실한 후에도 그런 표정을 지을 수 있을지 궁금하군요.`,JPN:`脳をえぐり理性を失った後も、そんな表情ができるのか見物ですね。`,ENG:`We shall see if you'll still make that face once we've carved your brain out.`,TWN:`等我把你的腦袋挖出來，我看你還能一臉囂張嗎！`},stage:{bg:`CORRIDOR_03`,slots:{L:null,C:{char_id:`HOLY_KNIGHT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`HOLY_KNIGHT_NULL_NULL`,text:{KOREA:`아, 걱정은 마세요. 저는 부활의 성녀, 루크레시아.`,JPN:`心配は要りません。私は復活の聖女、ルクレシア。`,ENG:`Oh, don't worry. I am the Saintess of Resurrection, after all.`,TWN:`喔！不過不用擔心，因為我可是復活的聖女 露可蕾西亞。`},stage:{bg:`CORRIDOR_03`,slots:{L:null,C:{char_id:`HOLY_KNIGHT_NULL_NULL`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`HOLY_KNIGHT_NULL_NULL`,text:{KOREA:`비록 산송장으로 만들더라도 결코 죽이지는 않을 테니까요.`,JPN:`空虚な抜け殻にしたとしても、決して殺すことはいたしません。`,ENG:`We may turn you into a living corpse, but we won't kill you.`,TWN:`我不會殺死你的，我會把你做成活死人。`},stage:{bg:`CORRIDOR_03`,slots:{L:null,C:{char_id:`HOLY_KNIGHT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};